"use strict";(self.webpackChunkrrbtc_wiki_docusaurus=self.webpackChunkrrbtc_wiki_docusaurus||[]).push([[6137],{2951(e){e.exports=JSON.parse('{"tag":{"label":"bitcoin","permalink":"/tags/bitcoin","allTagsPath":"/tags","count":12,"items":[{"id":"concepts/bitcoin-address-types","title":"Bitcoin Address Types","description":"Bitcoin addresses are human-readable encodings of scriptPubKeys \u2014 the spending conditions that lock bitcoin to a specific key or set of keys. Over time, address formats have evolved to improve efficiency, privacy, and compatibility.","permalink":"/concepts/bitcoin-address-types"},{"id":"entities/bitcoin-core","title":"Bitcoin Core","description":"Bitcoin Core is the reference implementation of the Bitcoin protocol. Originally released by Satoshi Nakamoto in 2009 as \\"Bitcoin,\\" it remains the most widely used, reviewed, and trusted node software.","permalink":"/entities/bitcoin-core"},{"id":"comparisons/bitcoin-core-vs-knots","title":"Bitcoin Core vs Bitcoin Knots","description":"Both are full-node implementations of the Bitcoin protocol. They follow identical consensus rules \u2014 neither can create or accept invalid blocks \u2014 but they differ in mempool policy: the set of rules each node uses to decide which unconfirmed transactions to accept, relay, and mine.","permalink":"/comparisons/bitcoin-core-vs-knots"},{"id":"concepts/bitcoin-node-types","title":"Bitcoin Node Types","description":"A Bitcoin node is any computer running software that enforces the consensus rules of the network. Not all nodes serve the same purpose \u2014 they range from passive validators to active infrastructure participants.","permalink":"/concepts/bitcoin-node-types"},{"id":"concepts/bitcoin-protocol","title":"Bitcoin Protocol","description":"The Bitcoin protocol is a set of consensus rules governing peer-to-peer electronic cash. First released by Satoshi Nakamoto in 2009, it combines cryptography, game theory, and distributed systems to create a monetary network without central authority.","permalink":"/concepts/bitcoin-protocol"},{"id":"concepts/no-kyc-acquisition","title":"No-KYC Acquisition Methods","description":"Acquiring bitcoin without identity verification preserves financial privacy, reduces third-party trust, and protects against data breaches. These methods range from low-effort (vouchers) to high-effort (mining), with varying privacy guarantees.","permalink":"/concepts/no-kyc-acquisition"},{"id":"summaries/privacy-as-a-spectrum","title":"Privacy as a Spectrum","description":"Privacy is not a feature you add to Bitcoin after the fact. It is a prerequisite for fungibility: the property that makes one satoshi interchangeable with any other. Without privacy, transactions become targets for censorship, surveillance, and discrimination. The blockchain is permanent; any link you create between your identity and your UTXOs cannot be undone.","permalink":"/summaries/privacy-as-a-spectrum"},{"id":"concepts/privacy-stacks","title":"Privacy Stacks","description":"Privacy in Bitcoin is not a single tool \u2014 it is a layered practice combining network hygiene, transaction obfuscation, and operational security (OPSEC). The goal is to selectively reveal data instead of broadcasting it by default.","permalink":"/concepts/privacy-stacks"},{"id":"comparisons/privacy-stacks","title":"Privacy Stacks \u2014 CoinJoin and No-KYC Acquisition","description":"Privacy in Bitcoin is not a single tool \u2014 it is a layered practice. This comparison focuses on the two most critical layers: how you acquire bitcoin without KYC and how you break the transaction graph after acquisition.","permalink":"/comparisons/privacy-stacks"},{"id":"concepts/proof-of-work","title":"Proof of Work & Bitcoin Supply","description":"Bitcoin uses Proof of Work (PoW) as its consensus mechanism. Miners compete to find a hash below a network-adjusted target, expending real-world energy to secure the ledger and issue new bitcoin.","permalink":"/concepts/proof-of-work"},{"id":"entities/start-os","title":"StartOS","description":"StartOS (formerly Start9OS) is a Debian-based operating system designed specifically for self-hosting Bitcoin and Lightning infrastructure. It packages complex services into one-click installs with automatic Tor and LAN access.","permalink":"/entities/start-os"},{"id":"concepts/utxo-model","title":"UTXO Model","description":"Bitcoin does not use an \\"account balance\\" system like a bank. Instead, it tracks Unspent Transaction Outputs (UTXOs) \u2014 discrete chunks of bitcoin that have been received but not yet spent.","permalink":"/concepts/utxo-model"}],"unlisted":false}}')}}]);